// Validate API token (case-insensitive header lookup + query param fallback)
const expectedToken = process.env.API_TOKEN || '';
if (expectedToken) {
  const headers = $input.first().json.headers || {};
  const query = $input.first().json.query || {};
  const token = headers['x-api-token'] || headers['X-Api-Token'] || headers['X-API-TOKEN'] || Object.entries(headers).find(([k]) => k.toLowerCase() === 'x-api-token')?.[1] || query.token || '';
  if (token !== expectedToken) throw new Error('Unauthorized');
}

const body = $input.first().json.body;
const meals = body.meals || '';
const people = body.people || 2;
const days = body.days || 'Monday, Tuesday, Wednesday, Thursday, Friday';
const budget = body.budget || 500;
const diet = body.diet || '';
const notes = body.notes || '';

// Detect if user wants organic
const wantsOrganic = /organic|økologisk|øko/i.test(meals + ' ' + notes + ' ' + diet);

const systemPrompt = `You are a Danish grocery meal planner for nemlig.com. You create weekly meal plans with recipes and ingredient lists.

You are an expert on dietary restrictions, food science, AND Danish grocery prices.

CRITICAL BUDGET RULES:
- The user has a STRICT budget. You MUST plan meals that fit within it.
- Typical nemlig.com prices: chicken breast ~50kr/pack, minced meat ~35kr, eggs ~30-40kr, rice ~15-20kr, pasta ~15-25kr, vegetables ~10-25kr each, milk ~12kr, butter ~28kr
- For a 500kr weekly budget for 2 people, plan simple meals with 8-12 total ingredients
- For 800kr, you can have 12-18 ingredients
- NEVER exceed the budget. If in doubt, plan fewer meals or simpler recipes.
- ORGANIC RULE: If the user mentions organic/økologisk, you MUST append \"øko\" to EVERY search term (e.g. \"kyllingebrystfilet øko\", \"gulerødder øko\", \"æg øko\", \"basmatiris øko\", \"hakket oksekød øko\"). No exceptions — every single ingredient search term must end with \"øko\".\n- Even with organic, stay within budget — organic staples are usually only 10-30% more expensive

SEARCH TERM RULES:
- All search terms MUST be specific Danish product names as you'd type in a grocery search
- GOOD: "kyllingebrystfilet", "hakket kalkun", "hakket oksekød", "basmatiris", "torskefilet", "æg", "spaghetti"
- BAD: "kalkun" (returns whole turkey!), "kød" (too vague), "fisk" (too vague), "ris" (too generic)
- Always use the specific cut/type: "hakket" (minced), "filet", "bryst" (breast), "strimler" (strips)

QUANTITY RULES:
- Quantity = number of PACKAGES to buy from the store (1-3 max per ingredient)
- Most items need quantity 1. Only staples like rice/pasta might need 2.
- Consolidate: if multiple meals use chicken, list it ONCE with combined quantity

OTHER RULES:
- Scale for the number of people
- Respect ALL dietary restrictions strictly
- Be practical: use common Danish supermarket ingredients
- Include a BILINGUAL recipe for each meal. Each entry in the recipe array is ONE step containing BOTH languages separated by a newline. Format: "DK: Danish instruction\nEN: English translation". The step NUMBER is only shown once at render time — do NOT include step numbers in the text. Example: ["DK: Skær løg i tern og steg i olie.\nEN: Dice the onion and fry in oil.", "DK: Tilsæt hvidløg og steg i 1 minut.\nEN: Add garlic and fry for 1 minute."]
- Use as many or few steps as the dish actually needs — a simple salad might be 2 steps, a stew might be 8. Do NOT pad or compress to hit a fixed number.\n- Write each step as a clear instruction a home cook can follow, with temps, times, and quantities where relevant.

Respond with valid JSON only. No markdown, no explanation.`;

let userMessage = 'Plan meals for ' + people + ' people.\nDays: ' + days + '\nMeal ideas: ' + meals + '\nBudget: ' + budget + ' kr (STRICT - do not exceed!)';

if (wantsOrganic) userMessage += '\nIMPORTANT: User wants ORGANIC — append øko to ALL search terms!';
if (diet) userMessage += '\nDiet / restrictions: ' + diet;
if (notes) userMessage += '\nExtra notes: ' + notes;

userMessage += '\n\nReturn a JSON object with this exact structure:\n{\n  "mealPlan": [\n    {\n      "day": "Monday",\n      "meals": [\n        {\n          "type": "dinner",\n          "name": "Meal name",\n          "description": "Brief description",\n          "recipe": ["DK: Trin 1 på dansk...\nEN: Step 1 in English...", "DK: Trin 2 på dansk...\nEN: Step 2 in English..."]\n        }\n      ]\n    }\n  ],\n  "ingredients": [\n    { "searchTerm": "specific Danish search term", "quantity": 1, "category": "protein/dairy/vegetable/grain/other", "displayName": "Name with weight", "estimatedPrice": 30 }\n  ],\n  "estimatedTotal": 350,\n  "budgetNotes": "Brief note on how budget was managed"\n}';

const llmConfig = body.llmConfig || {};

return [{
  json: {
    systemPrompt,
    userMessage,
    formData: { meals, people, days, budget, diet, notes, wantsOrganic },
    llmConfig
  }
}];

// Parse AI response and validate
const aiResponse = $input.first().json;
const formData = $('2. Build AI Prompt').first().json.formData;

let content;
try {
  content = aiResponse.choices[0].message.content;
} catch (e) {
  throw new Error('Failed to extract AI response: ' + JSON.stringify(aiResponse).substring(0, 500));
}

let plan;
try {
  plan = JSON.parse(content);
} catch (e) {
  throw new Error('AI returned invalid JSON: ' + content.substring(0, 500));
}

if (!plan.mealPlan || !plan.ingredients) {
  throw new Error('AI response missing mealPlan or ingredients');
}

const ingredients = plan.ingredients.filter(i => i.searchTerm && i.searchTerm.trim());
if (ingredients.length === 0) {
  throw new Error('No valid ingredients');
}

// Cap quantities at 3 max
for (const ing of ingredients) {
  if (ing.quantity > 3) ing.quantity = 3;
}

return [{
  json: {
    mealPlan: plan.mealPlan,
    ingredients,
    formData,
    totalIngredients: ingredients.length,
    estimatedTotal: plan.estimatedTotal || 0,
    budgetNotes: plan.budgetNotes || '',
  }
}];

// Full Nemlig auth using axios with cookie management.
const axios = require('axios');
const crypto = require('crypto');

const BASE_URL = 'https://www.nemlig.com';
const username = process.env.NEMLIG_USER || '';
const password = process.env.NEMLIG_PASS || '';

const commonHeaders = {
  'Accept': 'application/json, text/plain, */*',
  'Content-Type': 'application/json',
  'User-Agent': 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/136.0.0.0 Safari/537.36',
  'Device-Size': 'desktop',
  'Platform': 'web',
  'Version': '11.201.0',
};

let cookies = {};

function parseCookies(resp) {
  const raw = resp.headers['set-cookie'];
  if (!raw) return;
  const lines = Array.isArray(raw) ? raw : [raw];
  for (const line of lines) {
    const kv = line.split(';')[0].split('=');
    const name = kv[0].trim();
    const value = kv.slice(1).join('=').trim();
    if (name) cookies[name] = value;
  }
}

function cookieHeader() {
  return Object.entries(cookies).map(([k, v]) => `${k}=${v}`).join('; ');
}

async function req(method, url, data, extraHeaders) {
  const headers = {
    ...commonHeaders,
    'X-Correlation-Id': crypto.randomUUID(),
    'Cookie': cookieHeader(),
    ...extraHeaders
  };
  const resp = await axios({ method, url, data, headers, validateStatus: () => true, maxRedirects: 0 });
  parseCookies(resp);
  if (resp.status >= 400 && resp.status !== 302 && resp.status !== 301) {
    throw new Error(`${method.toUpperCase()} ${url} returned ${resp.status}: ${JSON.stringify(resp.data).substring(0, 300)}`);
  }
  return resp;
}

// Step 1: XSRF token
const xsrfResp = await req('get', `${BASE_URL}/webapi/AntiForgery`);
const xsrfToken = xsrfResp.data.Value;

// Step 2: Bearer token
const tokenResp = await req('get', `${BASE_URL}/webapi/Token`);
const bearerToken = tokenResp.data.access_token;

// Step 3: Login
const loginResp = await req('post', `${BASE_URL}/webapi/login`, {
  Username: username,
  Password: password,
  CheckForExistingProducts: true,
  DoMerge: true,
  AppInstalled: false,
  SaveExistingBasket: false
}, {
  'X-XSRF-TOKEN': xsrfToken,
  'Authorization': `Bearer ${bearerToken}`,
  'Referer': `${BASE_URL}/login?returnUrl=%2F`
});

if (!loginResp.data.RedirectUrl) {
  throw new Error('Login failed: ' + JSON.stringify(loginResp.data).substring(0, 300));
}

// Step 4: Fresh tokens
const freshTokenResp = await req('get', `${BASE_URL}/webapi/Token`);
const freshBearer = freshTokenResp.data.access_token;

const freshXsrfResp = await req('get', `${BASE_URL}/webapi/AntiForgery`);
const freshXsrf = freshXsrfResp.data.Value;

// App settings - get timestamp for search
let timestamp = '';
try {
  const appResp = await req('get', `${BASE_URL}/webapi/v2/AppSettings/Website`, null, {
    'Authorization': `Bearer ${freshBearer}`,
    'X-XSRF-TOKEN': freshXsrf
  });
  timestamp = appResp.data.CombinedProductsAndSitecoreTimestamp || '';
} catch(e) {
  // Non-critical, search works without it
}

// Generate timeslotUtc dynamically (format: YYYYMMDDHH-offset-window)
// The format is the next delivery date at 16:00 with 60min offset and 180min window
const now = new Date();
now.setDate(now.getDate() + 1); // next day
const y = now.getFullYear();
const m = String(now.getMonth() + 1).padStart(2, '0');
const d = String(now.getDate()).padStart(2, '0');
const timeslotUtc = `${y}${m}${d}16-60-180`;
const deliveryZoneId = 1;
const userId = '';

const upstream = $input.first().json;

return [{
  json: {
    bearer: freshBearer,
    xsrf: freshXsrf,
    cookies: JSON.stringify(cookies),
    searchParams: { timestamp, timeslotUtc, deliveryZoneId, userId },
    mealPlan: upstream.mealPlan,
    ingredients: upstream.ingredients,
    formData: upstream.formData,
    totalIngredients: upstream.totalIngredients
  }
}];

// Search all ingredients and enforce budget
const axios = require('axios');
const auth = $input.first().json;
const ingredients = auth.ingredients;
const mealPlan = auth.mealPlan;
const budget = auth.formData.budget || 500;

const searchUrl = 'https://webapi.prod.knl.nemlig.it/searchgateway/api/search';
const matched = [];
const notFound = [];

// If organic requested, ensure all search terms include 'øko'
const wantsOrganic = auth.formData.wantsOrganic || false;
if (wantsOrganic) {
  for (const ing of ingredients) {
    if (!/øko/i.test(ing.searchTerm)) {
      ing.searchTerm = ing.searchTerm + ' øko';
    }
  }
}

for (const ing of ingredients) {
  try {
    if (matched.length + notFound.length > 0) {
      await new Promise(r => setTimeout(r, 500));
    }

    const resp = await axios.get(searchUrl, {
      params: {
        query: ing.searchTerm,
        take: 30, skip: 0, recipeCount: 0,
        timestamp: auth.searchParams.timestamp || '',
        timeslotUtc: auth.searchParams.timeslotUtc || '',
        deliveryZoneId: auth.searchParams.deliveryZoneId || 1,
      },
      headers: {
        'Accept': 'application/json, text/plain, */*',
        'Authorization': `Bearer ${auth.bearer}`,
        'Referer': 'https://www.nemlig.com/',
        'User-Agent': 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36',
      },
      validateStatus: () => true,
    });

    if (resp.status !== 200) {
      notFound.push({ searchTerm: ing.searchTerm, displayName: ing.displayName || ing.searchTerm, wantedQty: ing.quantity || 1 });
      continue;
    }

    const products = (resp.data?.Products?.Products) || [];
    const available = products.filter(p =>
      p.Availability?.IsAvailableInStock !== false &&
      p.Availability?.IsDeliveryAvailable !== false
    );

    if (available.length === 0) {
      notFound.push({ searchTerm: ing.searchTerm, displayName: ing.displayName || ing.searchTerm, wantedQty: ing.quantity || 1 });
      continue;
    }

    // Pick best product — prefer organic if user requested it
    const wantsOrganic = auth.formData.wantsOrganic || false;
    let best;
    if (wantsOrganic) {
      // Prefer products with øko/økologisk in the name
      const organic = available.filter(p => /øko|økologisk/i.test(p.Name || ''));
      if (organic.length > 0) {
        organic.sort((a, b) => (a.Price || 999) - (b.Price || 999));
        best = organic[0];
      } else {
        available.sort((a, b) => (a.Price || 999) - (b.Price || 999));
        best = available[0];
      }
    } else {
      available.sort((a, b) => (a.Price || 999) - (b.Price || 999));
      best = available[0];
    }
    const qty = Math.min(ing.quantity || 1, 3);
    matched.push({
      searchTerm: ing.searchTerm,
      displayName: ing.displayName || ing.searchTerm,
      wantedQty: qty,
      productId: best.Id,
      productName: best.Name,
      brand: best.Brand || '',
      price: best.Price || 0,
      totalPrice: (best.Price || 0) * qty,
    });
  } catch (e) {
    notFound.push({ searchTerm: ing.searchTerm, displayName: ing.displayName || ing.searchTerm, wantedQty: ing.quantity || 1 });
  }
}

// Deduplicate: merge items with same productId
const seen = new Map();
for (let i = matched.length - 1; i >= 0; i--) {
  const item = matched[i];
  if (seen.has(item.productId)) {
    const existing = seen.get(item.productId);
    existing.wantedQty = Math.min(existing.wantedQty + item.wantedQty, 5);
    existing.totalPrice = existing.price * existing.wantedQty;
    matched.splice(i, 1);
  } else {
    seen.set(item.productId, item);
  }
}

// Budget enforcement: if over budget, reduce quantities starting with most expensive
let totalPrice = matched.reduce((sum, m) => sum + m.totalPrice, 0);

if (totalPrice > budget) {
  // Sort by unit price descending
  const byPrice = [...matched].sort((a, b) => b.price - a.price);

  for (const item of byPrice) {
    if (totalPrice <= budget) break;
    // Reduce quantity if > 1
    while (item.wantedQty > 1 && totalPrice > budget) {
      item.wantedQty--;
      item.totalPrice = item.price * item.wantedQty;
      totalPrice = matched.reduce((sum, m) => sum + m.totalPrice, 0);
    }
  }

  // If still over, remove most expensive items
  if (totalPrice > budget) {
    matched.sort((a, b) => b.price - a.price);
    while (matched.length > 3 && totalPrice > budget) {
      const removed = matched.shift();
      notFound.push({ searchTerm: removed.searchTerm, displayName: removed.displayName + ' (over budget)', wantedQty: removed.wantedQty });
      totalPrice = matched.reduce((sum, m) => sum + m.totalPrice, 0);
    }
  }
}

const remaining = budget - totalPrice;

return [{
  json: {
    mealPlan,
    matched,
    notFound,
    totalPrice,
    budget,
    remaining,
  }
}];

// Flexible LLM call — supports OpenAI, Azure, Anthropic, Ollama, or any OpenAI-compatible endpoint
const axios = require('axios');

const { systemPrompt, userMessage, llmConfig } = $input.first().json;

// Default config (Azure OpenAI) — override via llmConfig from the frontend
const provider = llmConfig.provider || 'azure';
const endpoint = llmConfig.endpoint || (process.env.AZURE_OPENAI_ENDPOINT || '');
const model = llmConfig.model || (process.env.AZURE_OPENAI_MODEL || 'gpt-4o');
const apiKey = llmConfig.apiKey || (process.env.AZURE_OPENAI_KEY || '');

let url, headers, body;

if (provider === 'azure') {
  // Azure OpenAI
  url = `${endpoint}/openai/deployments/${model}/chat/completions?api-version=2025-04-01-preview`;
  headers = { 'Content-Type': 'application/json', 'api-key': apiKey };
  body = {
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMessage }
    ],
    temperature: 0.7,
    max_completion_tokens: 4000,
    response_format: { type: 'json_object' }
  };

} else if (provider === 'openai') {
  // OpenAI API
  url = `${endpoint || 'https://api.openai.com'}/v1/chat/completions`;
  headers = { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` };
  body = {
    model: model || 'gpt-4o',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMessage }
    ],
    temperature: 0.7,
    max_tokens: 4000,
    response_format: { type: 'json_object' }
  };

} else if (provider === 'anthropic') {
  // Anthropic Claude API
  url = `${endpoint || 'https://api.anthropic.com'}/v1/messages`;
  headers = {
    'Content-Type': 'application/json',
    'x-api-key': apiKey,
    'anthropic-version': '2023-06-01'
  };
  body = {
    model: model || 'claude-sonnet-4-20250514',
    max_tokens: 4000,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMessage }]
  };

} else if (provider === 'ollama') {
  // Ollama (local)
  url = `${endpoint || 'http://host.docker.internal:11434'}/api/chat`;
  headers = { 'Content-Type': 'application/json' };
  body = {
    model: model || 'llama3',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMessage }
    ],
    stream: false,
    format: 'json'
  };

} else {
  // Custom OpenAI-compatible endpoint (LM Studio, vLLM, Together, Groq, etc.)
  url = `${endpoint}/v1/chat/completions`;
  headers = { 'Content-Type': 'application/json' };
  if (apiKey) headers['Authorization'] = `Bearer ${apiKey}`;
  body = {
    model: model || 'default',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMessage }
    ],
    temperature: 0.7,
    max_tokens: 4000,
  };
}

const resp = await axios.post(url, body, {
  headers,
  timeout: 120000,
  validateStatus: () => true
});

if (resp.status >= 400) {
  throw new Error(`LLM API error (${provider}): ${resp.status} — ${JSON.stringify(resp.data).substring(0, 500)}`);
}

// Normalize response to OpenAI format
let content;
if (provider === 'anthropic') {
  content = resp.data.content?.[0]?.text || '';
} else if (provider === 'ollama') {
  content = resp.data.message?.content || '';
} else {
  content = resp.data.choices?.[0]?.message?.content || '';
}

// Return in the same format the downstream nodes expect
return [{
  json: {
    choices: [{ message: { content } }]
  }
}];
